    int peopleAwareOfSecret(int n, int delay, int forget) {
        const int MOD = 1e9 + 7;
        vector<int> dp(n + 1);
        dp[1] = 1;
        for (int i = 2; i <= n; ++i) {
            for (int j = max(1, i - forget); j <= i - delay; ++j) {
                dp[i] = (dp[i] + dp[j]) % MOD;
            }
        }
        return dp[n];
    }
};
